async function loadUser(id) {
  if (!id) {
    return next(new Error('Missing user ID'));
  }

  try {
    const user = await db.findUser(id);
    if (!user) {
      return next(new Error('User not found'));
    }

    await audit.log('user_loaded', { userId: id });
    await cache.set(`user:${id}`, user);

    return user;
  } catch (err) {
    next(err);
  }
}
